parameters.text:
=You are a legal contract specialist. Generate a professional contract based on the following:

Contract Type: {{ $('Prepare Contract Data').first().json.contractType }}
Template: {{ $json.templateType }}
Base Terms: {{ $json.baseTerms }}
Custom Terms Requested: {{ $('Prepare Contract Data').first().json.customTerms || 'None specified' }}
Parties: {{ JSON.stringify($('Prepare Contract Data').first().json.parties) }}
Effective Date: {{ $('Prepare Contract Data').first().json.effectiveDate }}
Contract Value: {{ $('Prepare Contract Data').first().json.value }} {{ $('Prepare Contract Data').first().json.currency }}

Generate the contract in Markdown format with the following structure:
1. Title and Contract ID
2. Parties section
3. Recitals/Background
4. Key Terms and Conditions
5. Obligations of each party
6. Payment terms (if applicable)
7. Term and termination
8. Confidentiality clause
9. Governing law
10. Signature blocks

Return ONLY valid JSON with keys:
- contractMarkdown: The full contract in Markdown format
- suggestedClauses: Array of 3 additional recommended clauses
- riskAssessment: Brief assessment of contract risk level (low/medium/high) with reason

parameters.jsCode:
const contractData = $('Prepare Contract Data').first().json;
const aiResponse = $input.first().json;

let parsedContent = {};
try {
  const outputText = aiResponse.output || '{}';
  const jsonMatch = outputText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsedContent = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  parsedContent = {
    contractMarkdown: '# Contract\n\nError generating contract content.',
    suggestedClauses: ['Force Majeure', 'Dispute Resolution', 'Amendment Process'],
    riskAssessment: 'medium - Unable to fully assess'
  };
}

return [{
  json: {
    ...contractData,
    contractMarkdown: parsedContent.contractMarkdown || '# Contract Document',
    suggestedClauses: parsedContent.suggestedClauses || [],
    riskAssessment: parsedContent.riskAssessment || 'medium',
    generatedAt: new Date().toISOString()
  }
}];

const data = $input.first().json;
const parties = data.parties || [];

const signers = parties.map((party, index) => ({
  signerId: 'signer_' + (index + 1),
  name: party.name,
  email: party.email,
  role: party.role || 'Signatory',
  order: index + 1
}));

return [{
  json: {
    ...data,
    signers: signers,
    documentTitle: data.templateType + ' - ' + data.contractId,
    signingDeadline: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
    webhookUrl: $execution.resumeUrl
  }
}];

parameters.message:
=Dear Signatory,

A contract document is ready for your signature.

Contract ID: {{ $json.contractId }}
Document: {{ $json.documentTitle }}
Deadline: {{ $json.signingDeadline }}

Please review and sign the document at your earliest convenience.

Best regards,
Contract Management System

parameters.jsCode:
const webhookData = $input.first().json;
const originalData = $('Prepare Signature Request').first().json;

const isComplete = webhookData.body?.status === 'completed' || webhookData.body?.event === 'envelope_completed';
const isExpired = webhookData.body?.status === 'expired' || !webhookData.body;

return [{
  json: {
    contractId: originalData.contractId,
    documentTitle: originalData.documentTitle,
    status: isComplete ? 'SIGNED' : (isExpired ? 'EXPIRED' : 'PENDING'),
    signedAt: isComplete ? new Date().toISOString() : null,
    signers: originalData.signers,
    signatureDetails: webhookData.body || {},
    effectiveDate: originalData.effectiveDate,
    expirationDate: originalData.expirationDate,
    value: originalData.value,
    currency: originalData.currency
  }
}];

